document.addEventListener("DOMContentLoaded",function(){convertImages("img.injectable"),mobileMenu(),accordion(),smoothScroll(),headerScroll()});let convertImages=(e,o)=>{document.querySelectorAll(e).forEach(t=>{fetch(t.src).then(e=>e.text()).then(e=>{e=(new DOMParser).parseFromString(e,"image/svg+xml").querySelector("svg");if(!e)throw new Error("SVG not found");t.id&&(e.id=t.id),t.className&&(e.classList=t.classList),t.parentNode.replaceChild(e,t)}).then(()=>{"function"==typeof o&&o()}).catch(e=>console.error(e))})};function mobileMenu(){document.querySelector(".rd-header-mobile").addEventListener("click",function(){this.classList.toggle("open"),document.querySelector(".rd-header-mobile-menu").classList.toggle("open"),document.querySelector(".rd-header-mobile-top__icon").classList.toggle("open"),document.querySelectorAll(".rd-icon--handler").forEach(function(t){t.addEventListener("click",function(e){e.stopPropagation(),e.preventDefault();var e=t.closest(".rd-header-menu-top__link ");e.classList.toggle("open"),e&&(e=e.nextElementSibling)&&"ul"===e.tagName.toLowerCase()&&e.classList.toggle("open")})})})}function accordion(){document.querySelectorAll(".rd-media-faq").forEach(e=>{e.querySelectorAll(".rd-media-faq-item").forEach(t=>{t.querySelector(".rd-media-faq-question").addEventListener("click",()=>{var e=t.classList.contains("open");document.querySelectorAll(".rd-media-faq-item.open").forEach(e=>{e.classList.remove("open")}),e||t.classList.add("open")})});e=document.querySelector(".rd-media-faq-item");e&&e.classList.add("open")})}function smoothScroll(o=160){document.querySelectorAll('a[href^="#"]').forEach(e=>{e.addEventListener("click",function(e){var t=this.getAttribute("href").substring(1),t=document.getElementById(t);t&&(e.preventDefault(),e=t.getBoundingClientRect().top+window.pageYOffset,window.scrollTo({top:e-o,behavior:"smooth"}))})})}function headerScroll(){let e=document.querySelector(".rd-header");window.addEventListener("scroll",()=>{50<window.scrollY?e.classList.add("rd-header-scrolled"):e.classList.remove("rd-header-scrolled")})}jQuery;